prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?messageFlow WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask .
  OPTIONAL { ?task bbo:name ?taskName }

  ?messageFlow tai:belongsTo ?choreo ;
               a bboExt:MessageFlow .

  # Check if the message flow is connected to the task
  # MessageFlow uses string IDs for sourceRef/targetRef
  FILTER(CONTAINS(STR(?task), ?messageFlowSource) || CONTAINS(STR(?task), ?messageFlowTarget))
  ?messageFlow bboExt:sourceRef ?messageFlowSource ;
               bboExt:targetRef ?messageFlowTarget .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?prop (COUNT(*) as ?count) WHERE {
  ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  {
    ?task tai:belongsTo ?choreo ;
          a bboExt:ChoreographyTask .
    ?task ?prop ?value .
  }
  UNION
  {
    ?mf tai:belongsTo ?choreo ;
        a bboExt:MessageFlow .
    ?mf ?prop ?value .
  }
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName (COUNT(DISTINCT ?messageFlow) AS ?messageCount) WHERE {
  ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  ?messageFlow tai:belongsTo ?choreo ;
               a bboExt:MessageFlow ;
               bboExt:sourceRef ?sourceRef ;
               bboExt:targetRef ?targetRef .

  # Check if the task is the source or target of the message flow
  FILTER(?sourceRef = ?taskId || ?targetRef = ?taskId)
}
GROUP BY ?taskName
HAVING (COUNT(DISTINCT ?messageFlow) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?taskId ?sourceRef ?targetRef WHERE {
  ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  ?messageFlow tai:belongsTo ?choreo ;
               a bboExt:MessageFlow ;
               bboExt:sourceRef ?sourceRef ;
               bboExt:targetRef ?targetRef .
}
LIMIT 25
